//SPDX-License-Identifier:MIT

pragma solidity ^0.8.18;

import {AggregatorV3Interface} from "@chainlink/contracts/src/v0.8/shared/interfaces/AggregatorV3Interface.sol";


library PriceConverter{
    function getPrice() internal view returns (uint256) {
        // address 0x694AA1769357215DE4FAC081bf1f309aDC325306 => this address used to get the price values of ETH/USD
        // abi
        AggregatorV3Interface priceFeed = AggregatorV3Interface(0x694AA1769357215DE4FAC081bf1f309aDC325306);
        (, int256 answer,,, ) = priceFeed.latestRoundData();
        // answer = price of ETH in terms of USD
        return uint256(answer * 1e10);
    } // from the github and documentation of chainlink
    
    function getConvertionRate(uint256 ethAmount/*input*/) internal view returns (uint256){
        uint256 ethPrice = getPrice();
        uint256 ethAmountInUsd = (ethPrice * ethAmount) / 1e18;
        return ethAmountInUsd;
    } 

    function getVersion() internal view returns(uint256) {
       return AggregatorV3Interface(0x694AA1769357215DE4FAC081bf1f309aDC325306).version(); 
    } // In this function we are using the version() from the AggregatorV3Interface contract with the help of contract address interface and ABI
}

